import {useState} from 'react'
import {Button, Form} from 'react-bootstrap'
import abis from '../utils/abis'

const DeriMint = ({web3, bb}) => {
    const [amount, setAmount] = useState('')
    const account = '0x919735d147185788D8A29942baC49A5164A1Bfd6'
    const deri = new web3.eth.Contract(abis.Deri, '0xA487bF43cF3b10dffc97A9A744cbB7036965d3b9')

    const onMint = async () => {
        const nonce = await deri.methods.nonces(account).call()
        const deadline = parseInt(Date.now() / 86400000 + 1) * 86400
        const data = JSON.stringify({
            types: {
                EIP712Domain: [
                    {name: 'name', type: 'string'},
                    {name: 'chainId', type: 'uint256'},
                    {name: 'verifyingContract', type: 'address'}
                ],
                Mint: [
                    {name: 'account', type: 'address'},
                    {name: 'amount', type: 'uint256'},
                    {name: 'nonce', type: 'uint256'},
                    {name: 'deadline', type: 'uint256'}
                ],
            },
            primaryType: 'Mint',
            domain: {
                name: 'Deri',
                chainId: 1,
                verifyingContract: '0xA487bF43cF3b10dffc97A9A744cbB7036965d3b9'
            },
            message: {
                account: account,
                amount: bb(amount),
                nonce: nonce,
                deadline: deadline
            }
        })
        web3.currentProvider.sendAsync({
            method: 'eth_signTypedData_v3',
            params: [account, data],
            from: account
        }, async (err, result) => {
            if (err) {
                console.log(err)
            } else {
                const signature = result.result.substring(2)
                const r = '0x' + signature.substring(0, 64)
                const s = '0x' + signature.substring(64, 128)
                const v = parseInt(signature.substring(128, 130), 16)

                await deri.methods.mint(account, bb(amount), deadline, v, r, s).send({from: account})
            }
        })
    }

    return (
        <div>
            <h5>Deri Mint (ETH)</h5>
            <p><b>Signer: </b>{account}</p>
            <Form.Control value={amount} onChange={(e) => {setAmount(e.target.value)}} />
            <Button onClick={onMint}>Mint</Button>
        </div>
    )
}

export default DeriMint
