import {useState, useEffect} from 'react'
import abis from '../utils/abis'
import {Button} from 'react-bootstrap'

const OracleSwitchV2Polygon = ({web3, nn}) => {
    const oracles = {
        wooBTCUSD: '0x55fb310E3E36A2CfbB582Ce0B5B3f323bDEF2E4d',
        wooETHUSD: '0x1B531b26f1844c3479C6A5A518C2F3317f52D954',
        chainlinkBTCUSD: '0xa9C75fb1CE5196Bb9378E128aCe516836B169D59',
        chainlinkETHUSD: '0x608BF34A55d65441DA93363Dd3dB4369a981454e',
        routerBTCUSD: '0x58852B31d574d9F4301048112ae356fD6cb2C55b',
        routerETHUSD: '0x2369234686c180AFc079857A10872c6aE37A165c',
    }
    const signer = '0x80b4d014aa41EFf99083336bbeAe378617CFf076'
    const [activeOracles, setActiveOracles] = useState({})
    const [prices, setPrices] = useState({})

    useEffect(() => {(async () => {
        const newActiveOracles = await getActiveOracles()
        const newPrices = await getPrices()
        setActiveOracles({...activeOracles, ...newActiveOracles})
        setPrices({...prices, ...newPrices})
    })()}, [])

    const getActiveOracles = async () => {
        const newActiveOracles = {}
        const routers = ['routerBTCUSD', 'routerETHUSD']
        for (const name of routers) {
            const contract = new web3.eth.Contract(abis.OracleRouter, oracles[name])
            newActiveOracles[name] = await contract.methods.oracle().call()
        }
        return newActiveOracles
    }

    const getPrices = async () => {
        const newPrices = {}
        for (const [name, address] of Object.entries(oracles)) {
            const contract = new web3.eth.Contract(abis.Oracle, address)
            newPrices[name] = await contract.methods.getPrice().call()
        }
        return newPrices
    }

    const switchOracle = async (symbol) => {
        const router = new web3.eth.Contract(abis.OracleRouter, oracles[`router${symbol}`])
        const target = activeOracles[`router${symbol}`] === oracles[`woo${symbol}`] ? oracles[`chainlink${symbol}`] : oracles[`woo${symbol}`]
        await router.methods.setOracle(target).send({from: signer})
        const newActiveOracles = await getActiveOracles()
        const newPrices = await getPrices()
        setActiveOracles({...activeOracles, ...newActiveOracles})
        setPrices({...prices, ...newPrices})
    }

    return (
        <div>
            <br/>
            <h5>Deri V2 Oracle Switch (Polygon)</h5>
            <p><b>Signer: </b>{signer}</p>
            <table>
            <tbody>
                <tr>
                    <th></th>
                    <th>WooTrade</th>
                    <th></th>
                    <th>Chainlink</th>
                    <th></th>
                    <th></th>
                </tr>
                <tr>
                    <th>BTCUSD</th>
                    <td bgcolor={activeOracles.routerBTCUSD === oracles.wooBTCUSD ? 'lightgreen' : ''}>{oracles.wooBTCUSD}</td>
                    <td bgcolor={prices.routerBTCUSD === prices.wooBTCUSD ? 'lightgreen' : ''}>{nn(prices.wooBTCUSD)}</td>
                    <td bgcolor={activeOracles.routerBTCUSD === oracles.chainlinkBTCUSD ? 'lightgreen' : ''}>{oracles.chainlinkBTCUSD}</td>
                    <td bgcolor={prices.routerBTCUSD === prices.chainlinkBTCUSD ? 'lightgreen' : ''}>{nn(prices.chainlinkBTCUSD)}</td>
                    <td><Button onClick={() => switchOracle('BTCUSD')}>Switch to {activeOracles.routerBTCUSD === oracles.wooBTCUSD ? 'Chainlink' : 'WooTrade'}</Button></td>
                </tr>
                <tr>
                    <th>ETHUSD</th>
                    <td bgcolor={activeOracles.routerETHUSD === oracles.wooETHUSD ? 'lightgreen' : ''}>{oracles.wooETHUSD}</td>
                    <td bgcolor={prices.routerETHUSD === prices.wooETHUSD ? 'lightgreen' : ''}>{nn(prices.wooETHUSD)}</td>
                    <td bgcolor={activeOracles.routerETHUSD === oracles.chainlinkETHUSD ? 'lightgreen' : ''}>{oracles.chainlinkETHUSD}</td>
                    <td bgcolor={prices.routerETHUSD === prices.chainlinkETHUSD ? 'lightgreen' : ''}>{nn(prices.chainlinkETHUSD)}</td>
                    <td><Button onClick={() => switchOracle('ETHUSD')}>Switch to {activeOracles.routerETHUSD === oracles.wooETHUSD ? 'Chainlink' : 'WooTrade'}</Button></td>
                </tr>
            </tbody>
            </table>
        </div>
    )
}

export default OracleSwitchV2Polygon
