import 'bootstrap/dist/css/bootstrap.min.css'
import {useEffect} from 'react'
import Web3 from 'web3'

import DeriMint from './components/DeriMint'
import OracleSwitchV2 from './components/OracleSwitchV2'
import OracleSwitchV2Polygon from './components/OracleSwitchV2Polygon'
import OracleSwitchV3 from './components/OracleSwitchV3'

const ONE = new Web3.utils.BN('1000000000000000000')
const ZERO_ADDRESS = '0x0000000000000000000000000000000000000000'
const MAX = '0XFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF'

function nn(value, unit='ether') {
    return value ? Web3.utils.fromWei(value.toString(), unit) : undefined
}

function bb(value, unit='ether') {
    return value ? Web3.utils.toWei(value.toString(), unit) : undefined
}

function App() {

    const web3 = new Web3(window.ethereum)

    useEffect(() => {(async () => {
        const chainId = await window.ethereum.request({'method': 'eth_chainId'})
        const accounts = await window.ethereum.request({'method': 'eth_requestAccounts'})
        console.log('chainId', chainId)
        console.log('account', accounts[0])
    })()}, [])

    window.ethereum.on('accountsChanged', (accounts) => {
        window.location.reload()
    })

    window.ethereum.on('chainChanged', (chainId) => {
        window.location.reload()
    })

    return (
        <div className="App">
            <h3>Deri Auxiliary (20220225)</h3>
            <br/>
            <DeriMint web3={web3} bb={bb}/>
            <br/>
            <OracleSwitchV2 web3={web3} nn={nn} />
            <br/>
            <OracleSwitchV2Polygon web3={web3} nn={nn} />
            <br/>
            <OracleSwitchV3 web3={web3} nn={nn} />
        </div>
    )

}

export default App
